"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[490088],{727908:e=>{e.exports=JSON.parse('{"tag":{"label":"spawning","permalink":"/dst-api-webdocs/docs/tags/spawning","allTagsPath":"/dst-api-webdocs/docs/tags","count":31,"items":[{"id":"game-scripts/components/beargerspawner","title":"Beargerspawner","description":"Manages spawning and timers for Bearger events in DST, tracking players, seasonal logic, and countdown warnings.","permalink":"/dst-api-webdocs/docs/game-scripts/components/beargerspawner"},{"id":"game-scripts/prefabs/beefaloherd","title":"Beefaloherd","description":"Manages a herd of beefalo, handling seasonal mating behavior, member aggregation, and automatic spawning of baby beefalo during mating season.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefaloherd"},{"id":"game-scripts/prefabs/beehive","title":"Beehive","description":"Manages hive behavior including bee spawning, seasonal rate adjustments, damage response, hauntable mechanics, and interactions with freezing and burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beehive"},{"id":"game-scripts/components/birdspawner","title":"Birdspawner","description":"Manages the spawning and behavior of birds in the game world, including timed spawning for players, lunar hail event responses, and dynamic environmental adjustments.","permalink":"/dst-api-webdocs/docs/game-scripts/components/birdspawner"},{"id":"game-scripts/map/bunches","title":"Bunches","description":"Defines static spawning rules for grouped environmental props (bunches) such as seastacks, saltstacks, and rubbles across specific tile types.","permalink":"/dst-api-webdocs/docs/game-scripts/map/bunches"},{"id":"game-scripts/prefabs/catcoonden","title":"Catcoonden","description":"Manages the lifecycle, inventory, and catcoon spawning behavior of the Catcoon Den structure in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/catcoonden"},{"id":"game-scripts/prefabs/cavelight","title":"Cavelight","description":"Manages dynamic lighting and spawning behavior for cave exit light sources, adjusting brightness, color, and presence based on world and cave phase states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cavelight"},{"id":"game-scripts/prefabs/cookiecutter_spawner","title":"Cookiecutter Spawner","description":"Spawns and manages Cookiecutter minions underwater, regenerating them over time based on tunable parameters and world settings.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cookiecutter_spawner"},{"id":"game-scripts/components/deciduoustreeupdater","title":"Deciduoustreeupdater","description":"Manages the transformation of a deciduous tree into a hostile monster state, controlling drake spawning, root attacks, and state transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/deciduoustreeupdater"},{"id":"game-scripts/components/deerclopsspawner","title":"Deerclopsspawner","description":"Manages the spawning, timing, and targeting logic for Deerclops boss attacks in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/deerclopsspawner"},{"id":"game-scripts/brains/dragonflybrain","title":"Dragonflybrain","description":"Manages AI behavior for the Dragonfly boss, including fight reset logic, Lavae spawning, chase/combat, and home patrolling.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/dragonflybrain"},{"id":"game-scripts/brains/eyeofterrorbrain","title":"Eyeofterrorbrain","description":"Controls the AI behavior of the Eye of Terror boss, coordinating special attacks, leashing, facing, and spawning mini-eyes via behavior trees.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/eyeofterrorbrain"},{"id":"game-scripts/prefabs/fishschoolspawnblocker","title":"Fishschoolspawnblocker","description":"Removes itself automatically after a fixed lifetime to prevent permanent obstruction of fish school spawn points.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fishschoolspawnblocker"},{"id":"game-scripts/components/flotsamgenerator","title":"Flotsamgenerator","description":"Spawns and manages floating debris (flotsam) in ocean environments, including scheduled natural spawns and guaranteed items like message bottles.","permalink":"/dst-api-webdocs/docs/game-scripts/components/flotsamgenerator"},{"id":"game-scripts/components/forestresourcespawner","title":"Forestresourcespawner","description":"Manages periodic spawning of renewable forest resources such as flint, saplings, and berry bushes near spawn points when no players are nearby.","permalink":"/dst-api-webdocs/docs/game-scripts/components/forestresourcespawner"},{"id":"game-scripts/components/gingerbreadhunter","title":"Gingerbreadhunter","description":"Manages the spawning and progression of gingerbread-themed hunts during events, including generating crumb trails and spawning gingerbread pigs or houses.","permalink":"/dst-api-webdocs/docs/game-scripts/components/gingerbreadhunter"},{"id":"game-scripts/prefabs/glommer","title":"Glommer","description":"A flying lunar-aligned companion entity that follows the player, enters sleep cycles, periodically spawns fuel items, and adjusts sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommer"},{"id":"game-scripts/prefabs/hermithouse","title":"Hermithouse","description":"Manages the hermit crab\u2019s home structure, including construction progression, friend-based recipe unlocking, hermit crab spawning, and pearl-based decoration scoring.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermithouse"},{"id":"game-scripts/components/lureplantspawner","title":"Lureplantspawner","description":"Manages the seasonal spawning of Lureplants during spring by tracking player movement trails and probabilistically placing them around active players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lureplantspawner"},{"id":"game-scripts/map/rooms/forest/merms","title":"Merms","description":"Defines the MermTown room template for forest worlds, specifying tile type, visual color, and spawn rules for merm-related structures and entities.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/merms"},{"id":"game-scripts/components/moosespawner","title":"Moosespawner","description":"Manages the spawning and scheduling of moose entities in relation to moose nesting grounds during spring season.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moosespawner"},{"id":"game-scripts/prefabs/oceanvine","title":"Oceanvine","description":"Manages the behavior, harvesting, burning, and dynamic spawing of ocean vines in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanvine"},{"id":"game-scripts/prefabs/oceanvine_cocoon","title":"Oceanvine Cocoon","description":"A flying spider cocoon that slowly spawns water spiders to hunt for ocean fish; it can be ignited or frozen, and drops silk, twigs, or ash upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanvine_cocoon"},{"id":"game-scripts/components/periodicspawner","title":"Periodicspawner","description":"Manages periodic spawning of prefabs at or around an entity with configurable timing, spatial density, and conditional logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/periodicspawner"},{"id":"game-scripts/prefabs/pigtorch","title":"Pigtorch","description":"A structure that produces guards and burns fuel over time, extinguishing when its fuel runs out or during rain.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch"},{"id":"game-scripts/components/rampingspawner","title":"Rampingspawner","description":"Manages progressive spawning of entities in waves, ramping up spawn count over time based on wave progression.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rampingspawner"},{"id":"game-scripts/components/shadowcreaturespawner","title":"Shadowcreaturespawner","description":"Manages the spawning, tracking, and population control of shadow creatures (e.g., Crawling Horrors, Ocean Horrors, Terrorbeaks) for players based on sanity levels and game mode.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowcreaturespawner"},{"id":"game-scripts/components/squidspawner","title":"Squidspawner","description":"Manages squid spawning based on player locations, moon phase, time of day, and nearby ocean trawlers during nights and dusk.","permalink":"/dst-api-webdocs/docs/game-scripts/components/squidspawner"},{"id":"game-scripts/prefabs/tallbirdnest","title":"Tallbirdnest","description":"Manages the tallbird nesting behavior, egg spawning, and seasonal reproduction cycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tallbirdnest"},{"id":"game-scripts/map/terrain","title":"Terrain","description":"Defines terrain tile restrictions for spawning in-game objects and provides access to room definitions via a deprecated lookup mechanism.","permalink":"/dst-api-webdocs/docs/game-scripts/map/terrain"},{"id":"game-scripts/components/wintersurprisespawner","title":"Wintersurprisespawner","description":"Manages the spawning of winter surprise trees during winter seasons, based on world state and player positioning rules.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wintersurprisespawner"}],"unlisted":false}}')}}]);